class Solution(object):
    def interpret(self, command):
        result = ""
        i = 0
        while i < len(command):
            if command[i] == 'G':
                result += 'G'
                i += 1
            elif command[i] == '(' and command[i+1] == ')':
                result += 'o'
                i += 2
            elif command[i] == '(' and command[i+1] == 'a':
                result += 'al'
                i += 4
        return result
